将C4矩阵转置，使C4[p][s]按列主序存储，然后修改内层循环为连续访问。同时添加分块优化：

DATA_TYPE POLYBENCH_2D(C4T,NP,NP,np,np);
// 初始化时转置C4
for (int i = 0; i < np; i++)
  for (int j = 0; j < np; j++)
    C4T[i][j] = C4[j][i];

// 修改内核，添加分块
const int BLOCK_SIZE = 32;
for (r = 0; r < _PB_NR; r++) {
  for (q = 0; q < _PB_NQ; q++) {
    for (p = 0; p < _PB_NP; p++)
      sum[p] = SCALAR_VAL(0.0);

    for (s = 0; s < _PB_NP; s += BLOCK_SIZE) {
      int s_end = MIN(s + BLOCK_SIZE, _PB_NP);
      for (p = 0; p < _PB_NP; p++) {
        DATA_TYPE temp = SCALAR_VAL(0.0);
        for (int ss = s; ss < s_end; ss++) {
          temp += A[r][q][ss] * C4T[p][ss];
        }
        sum[p] += temp;
      }
    }

    for (p = 0; p < _PB_NP; p++)
      A[r][q][p] = sum[p];
  }
}

利用编译器的向量化提示和手动循环展开：

#pragma omp simd
for (p = 0; p < _PB_NP; p += 4) {
  sum[p] = SCALAR_VAL(0.0);
  sum[p+1] = SCALAR_VAL(0.0);
  sum[p+2] = SCALAR_VAL(0.0);
  sum[p+3] = SCALAR_VAL(0.0);
}

// 内层循环使用向量化
#pragma omp simd reduction(+:temp)
for (int ss = s; ss < s_end; ss++) {
  temp += A[r][q][ss] * C4T[p][ss];
}

